INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIT Guwahati', 'ambassador_message', 'fests', 'Techniche Spirit Alcheringa Virasat are fests', 'IIT Guwahati hosts four major fests: Techniche (technical), Alcheringa (cultural), Spirit (sports), and Virasat (heritage/cultural).', 1, '31/03/26 7:02 pm', '31/03/26 7:02 pm', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIT Guwahati', 'ambassador_message', 'hostels', '13 hostels. Brahmaputra 1&2&mtech 1st year sharing 3&4&phd&mtech 2nd year single room same mess. Lohit Kapili Dihing Kameng Umiam Barak Siang Manas same. Gaurang mtech 1st year double sharing. Girls: Subhansiri Disang Dhansiri. Married scholar hostel.', 'IIT Guwahati has 13 hostels. Boys: Brahmaputra, Lohit, Kapili, Dihing, Kameng, Umiam, Barak, Siang, Manas all follow same pattern - 1st/2nd year sharing, 3rd/4th year single rooms, each has own mess. Gaurang is M.Tech 1st year double sharing. Girls: Subhansiri, Disang, Dhansiri same pattern. Married Scholar Hostel for married PhD.', 5, '31/03/26 7:04 pm', '31/03/26 7:17 pm', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIT Guwahati', 'ambassador_message', 'laundry', 'Laundry in all hostels. Paid laundry in lohit hostel', 'Laundry available in all hostels. Lohit hostel has paid laundry service.', 1, '31/03/26 7:19 pm', '31/03/26 7:19 pm', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIT Guwahati', 'ambassador_message', 'elections', 'VP of gymkhana council. General secretaries: sports board, student welfare board, hostel affairs board, student welfare committee, student academic board. Senators: UG PG Girls', 'Elections at IIT Guwahati: VP of Gymkhana Council, General Secretaries for Sports, Student Welfare, Hostel Affairs, Welfare Committee, Academic Board. Senators for UG, PG, and Girls.', 1, '31/03/26 7:23 pm', '31/03/26 7:23 pm', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIT Guwahati', 'ambassador_message', 'sports_canteen_gym', 'Cricket Badminton Table tennis Archery Lawn tennis Football Volleyball Athletics Kabbadi Kho kho. Every hostel has canteens. Lohit canteen closing time 4am remaining at 1am. Central gyms 2 for boys 1 for girls and every hostel has its own gym', 'Sports: Cricket, Badminton, TT, Archery, Lawn Tennis, Football, Volleyball, Athletics, Kabbadi, Kho Kho. Every hostel has canteen - Lohit till 4 AM, rest till 1 AM. 2 central gyms for boys, 1 for girls, plus every hostel has own gym.', 4, '31/03/26 7:25 pm', '31/03/26 7:31 pm', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIT Guwahati', 'ambassador_message', 'shops_fines', 'Cycle repair shop Tailor shop Footwear Laptop repair shop Salon General store. Registration fine of 500. Disciplinary fines', 'On-campus shops: Cycle repair, Tailor, Footwear, Laptop repair, Salon, General store. Fines: Registration fine Rs 500, disciplinary fines apply.', 2, '31/03/26 7:28 pm', '31/03/26 7:30 pm', 'whatsapp');
