INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIT Guwahati', 'ambassador_message', 'transport_restaurants_malls', 'Transport e autos e buggy paid. Khamakya 12km guwahati 9.1km railway. Airport 21km. Restaurants lauriat urban tadaka in campus. Swiggy zomato. Malls: NCS square 12km Zudio 9km West side 10km City Central 13km', 'Transport: E-autos and e-buggy (paid) on campus. Kamakhya Railway 12 km, Guwahati Railway 9.1 km, Airport 21 km. On-campus restaurants: Lauriat, Urban Tadka. Swiggy/Zomato deliver. Malls: NCS Square 12 km, Zudio 9 km, West Side 10 km, City Central 13 km.', 5, '31/03/26 7:35 pm', '31/03/26 7:44 pm', 'whatsapp');
