INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIT Guwahati', 'document_ocr', 'fee_structure', 'Fee structure B.Tech joining July 2025. 1st sem: Tuition 1L Hostel/Mess 33200 Deposit 12000 Other 20800 Total 166000. 2nd-8th sem ~143200 each. Total 4 years 1168400 plus Medical Insurance. Hostel includes rent maintenance electricity water mess advance 22000.', 'IIT Guwahati B.Tech fee (General/EWS/OBC-NCL, July 2025): 1st semester Rs 1,66,000. Subsequent semesters ~Rs 1,43,200 each + Medical Insurance. Total 4 years: Rs 11,68,400 + Medical Insurance. Hostel fee includes rent, maintenance, electricity, water, mess advance Rs 22,000/semester. Refundable deposit Rs 12,000 (1st sem only). One-time admission fee Rs 10,800.', 1, '31/03/26', '31/03/26', 'pdf_ocr');
